/**
 * SMS channel handler — delivers notifications via SMS.
 * Subscribes to `notification:requested` events on the EventBus and processes
 * those targeted at the 'sms' channel.
 */
export class SmsChannelHandler implements NotificationChannelHandler {
  readonly channel = 'sms';
  private logger = new Logger('SmsChannelHandler');
  private deliveredMessages: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      if (event.channel === this.channel) {
        this.handle(event);
      }
    });
  }

  handle(event: NotificationRequestedEvent): void {
    const notification: Notification = {
      id: generateNotificationId(),
      channel: this.channel,
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.deliveredMessages.push(notification);
    this.logger.info(`SMS sent: ${notification.id} to ${event.recipient}`);
  }

  getDeliveredMessages(): Notification[] {
    return [...this.deliveredMessages];
  }

  clearDeliveredMessages(): void {
    this.deliveredMessages = [];
  }
}

/**
 * Webhook channel handler — delivers notifications via HTTP webhooks.
 * Subscribes to `notification:requested` events on the EventBus and processes
 * those targeted at the 'webhook' channel.
 */
