  readonly channel = 'webhook';
  private logger = new Logger('WebhookChannelHandler');
  private deliveredPayloads: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      if (event.channel === this.channel) {
        this.handle(event);
      }
    });
  }

  handle(event: NotificationRequestedEvent): void {
    const notification: Notification = {
      id: generateNotificationId(),
      channel: this.channel,
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.deliveredPayloads.push(notification);
    this.logger.info(`Webhook delivered: ${notification.id} to ${event.recipient}`);
  }

  getDeliveredPayloads(): Notification[] {
    return [...this.deliveredPayloads];
  }

  clearDeliveredPayloads(): void {
    this.deliveredPayloads = [];
  }
}

