describe('SmsChannelHandler', () => {
  let eventBus: EventBus;
  let smsHandler: SmsChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    resetNotificationIdCounter();
    smsHandler = new SmsChannelHandler(eventBus);
  });

  it('should deliver SMS notifications from EventBus', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Alert',
      body: 'Your order has shipped!',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const messages = smsHandler.getDeliveredMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0]?.channel).toBe('sms');
    expect(messages[0]?.recipient).toBe('+1234567890');
    expect(messages[0]?.subject).toBe('Alert');
    expect(messages[0]?.body).toBe('Your order has shipped!');
  });

  it('should ignore non-sms channel notifications', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Welcome!',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
  });

  it('should handle multiple SMS notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'First',
      body: 'First SMS',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    await eventBus.emit({
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+0987654321',
      subject: 'Second',
      body: 'Second SMS',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    const messages = smsHandler.getDeliveredMessages();
    expect(messages).toHaveLength(2);
    expect(messages[0]?.recipient).toBe('+1234567890');
    expect(messages[1]?.recipient).toBe('+0987654321');
  });

  it('should clear delivered messages', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Test',
      body: 'Test',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    smsHandler.clearDeliveredMessages();
    expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
  });

  it('should work end-to-end with NotificationService', async () => {
    const service = new NotificationService(eventBus);
    resetNotificationIdCounter();

    service.dispatchNotification({
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Order Update',
      body: 'Your order has been confirmed.',
    });

    await new Promise((resolve) => setTimeout(resolve, 0));

    const messages = smsHandler.getDeliveredMessages();
    expect(messages).toHaveLength(1);
    expect(messages[0]?.recipient).toBe('+1234567890');
    expect(messages[0]?.body).toBe('Your order has been confirmed.');

    expect(service.getNotificationCount()).toBeGreaterThanOrEqual(1);
  });
});

describe('WebhookChannelHandler', () => {
  let eventBus: EventBus;
  let webhookHandler: WebhookChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    resetNotificationIdCounter();
    webhookHandler = new WebhookChannelHandler(eventBus);
  });

  it('should deliver webhook notifications from EventBus', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Order Created',
      body: '{"orderId":"order-1","status":"pending"}',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const payloads = webhookHandler.getDeliveredPayloads();
    expect(payloads).toHaveLength(1);
    expect(payloads[0]?.channel).toBe('webhook');
    expect(payloads[0]?.recipient).toBe('https://hooks.example.com/notify');
    expect(payloads[0]?.subject).toBe('Order Created');
    expect(payloads[0]?.body).toBe('{"orderId":"order-1","status":"pending"}');
  });

  it('should ignore non-webhook channel notifications', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Welcome!',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(webhookHandler.getDeliveredPayloads()).toHaveLength(0);
  });

  it('should handle multiple webhook notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/a',
      subject: 'First',
      body: 'First payload',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    await eventBus.emit({
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/b',
      subject: 'Second',
      body: 'Second payload',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    const payloads = webhookHandler.getDeliveredPayloads();
    expect(payloads).toHaveLength(2);
    expect(payloads[0]?.recipient).toBe('https://hooks.example.com/a');
    expect(payloads[1]?.recipient).toBe('https://hooks.example.com/b');
  });

  it('should clear delivered payloads', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Test',
      body: 'Test',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    webhookHandler.clearDeliveredPayloads();
    expect(webhookHandler.getDeliveredPayloads()).toHaveLength(0);
  });

  it('should work end-to-end with NotificationService', async () => {
    const service = new NotificationService(eventBus);
    resetNotificationIdCounter();

    service.dispatchNotification({
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Status Change',
      body: '{"orderId":"order-1","newStatus":"shipped"}',
    });

    await new Promise((resolve) => setTimeout(resolve, 0));

    const payloads = webhookHandler.getDeliveredPayloads();
    expect(payloads).toHaveLength(1);
    expect(payloads[0]?.recipient).toBe('https://hooks.example.com/notify');
    expect(payloads[0]?.body).toBe('{"orderId":"order-1","newStatus":"shipped"}');

    expect(service.getNotificationCount()).toBeGreaterThanOrEqual(1);
  });

  it('should coexist with other channel handlers on the same EventBus', async () => {
    const emailHandler = new EmailChannelHandler(eventBus);
    const smsHandler = new SmsChannelHandler(eventBus);

    await eventBus.emit({
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Email',
      body: 'Email body',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    await eventBus.emit({
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'SMS',
      body: 'SMS body',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    await eventBus.emit({
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Webhook',
      body: 'Webhook body',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
    expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
    expect(webhookHandler.getDeliveredPayloads()).toHaveLength(1);
  });
});

